# Find and replace the Q_NJFET_GDS symbol block (2-tab indent)
pattern = r'\t\t\(symbol "Device:Q_NJFET_GDS".*?\n\t\t\)'
match = re.search(pattern, content, re.DOTALL)
if match:
    print(f"Found at chars {match.start()}-{match.end()}")
    print(f"First 60 chars: {repr(match.group()[:60])}")
    print(f"Last 60 chars: {repr(match.group()[-60:])}")
    new_content = content[:match.start()] + new_symbol + content[match.end():]
    # Also replace lib_id references
    new_content = new_content.replace('(lib_id "Device:Q_NJFET_GDS")', '(lib_id "Device:Q_NMOS")')
    with open("PSN_TRX.kicad_sch", "w", encoding="utf-8") as f:
        f.write(new_content)
    print("Done!")
    remaining = new_content.count("Q_NJFET_GDS")
    nmos_lib = new_content.count('(lib_id "Device:Q_NMOS")')
    nmos_sym = new_content.count('(symbol "Device:Q_NMOS"')
    print(f"Remaining Q_NJFET_GDS references: {remaining}")
    print(f"lib_id Device:Q_NMOS count: {nmos_lib}")
    print(f"symbol Device:Q_NMOS count: {nmos_sym}")
else:
    print("Pattern not found!")
    idx = content.find('\t\t(symbol "Device:Q_NJFET_GDS"')
    print(f"2-tab find at: {idx}")
    # Show what the closing looks like
    if idx >= 0:
        end_search = content.find('\n\t\t)', idx)
        print(f"Closing at: {end_search}")
        print(f"Context around close: {repr(content[end_search-30:end_search+10])}")
